async function captureVisiblePage() {
  const canvas = document.createElement("canvas")
  const w = Math.max(document.documentElement.clientWidth, window.innerWidth || 0)
  const h = Math.max(document.documentElement.clientHeight, window.innerHeight || 0)
  canvas.width = w * (window.devicePixelRatio || 1)
  canvas.height = h * (window.devicePixelRatio || 1)
  const ctx = canvas.getContext("2d")
  ctx.scale(window.devicePixelRatio || 1, window.devicePixelRatio || 1)
  ctx.fillStyle = "#fff"
  ctx.fillRect(0, 0, w, h)
  ctx.fillStyle = "#000"
  ctx.font = "16px sans-serif"
  ctx.fillText("Screenshot capture via browser JS is not available without page-render APIs.", 20, 40)
  return await new Promise((resolve) => canvas.toBlob((blob) => {
    const a = document.createElement("a")
    a.href = URL.createObjectURL(blob)
    a.download = `screenshot-${Date.now()}.png`
    a.click()
    resolve("downloaded placeholder screenshot")
  }, "image/png"))
}
return await captureVisiblePage()

