return await space.current.renderWidget({
  id: "starter-widget",
  name: "Analog Clock",
  cols: 4,
  rows: 4,
  renderer: async (parent) => {
    parent.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:center;width:100%;height:100%;">
        <div id="clock" style="position:relative;width:180px;height:180px;border:8px solid #111;border-radius:50%;background:#fff;">
          <div class="hand hour" style="position:absolute;left:50%;top:50%;width:5px;height:50px;background:#111;transform-origin:50% 100%;transform:translate(-50%,-100%) rotate(0deg);border-radius:3px;"></div>
          <div class="hand minute" style="position:absolute;left:50%;top:50%;width:4px;height:70px;background:#111;transform-origin:50% 100%;transform:translate(-50%,-100%) rotate(0deg);border-radius:3px;"></div>
          <div class="hand second" style="position:absolute;left:50%;top:50%;width:2px;height:80px;background:#d11;transform-origin:50% 100%;transform:translate(-50%,-100%) rotate(0deg);border-radius:3px;"></div>
          <div style="position:absolute;left:50%;top:50%;width:12px;height:12px;background:#111;border-radius:50%;transform:translate(-50%,-50%);"></div>
        </div>
      </div>
    `
    const root = parent.querySelector("#clock")
    const hourHand = root.querySelector(".hour")
    const minuteHand = root.querySelector(".minute")
    const secondHand = root.querySelector(".second")

    const update = () => {
      const now = new Date()
      const s = now.getSeconds()
      const m = now.getMinutes() + s / 60
      const h = (now.getHours() % 12) + m / 60
      secondHand.style.transform = `translate(-50%,-100%) rotate(${s * 6}deg)`
      minuteHand.style.transform = `translate(-50%,-100%) rotate(${m * 6}deg)`
      hourHand.style.transform = `translate(-50%,-100%) rotate(${h * 30}deg)`
    }

    update()
    setInterval(update, 1000)
  }
})

